72	  const sinceDate = process.argv.includes('--since') ? process.argv[process.argv.indexOf('--since') + 1] : null;
73	  const onlyIds = process.argv.includes('--ids') ? process.argv[process.argv.indexOf('--ids') + 1].split(',') : null;
74	
75	  console.log('[API Batch] 连接 Chrome ...');
76	  const browser = await chromium.connectOverCDP(CDP_URL);
77	  const page = browser.contexts()[0].pages().find(p => p.url().includes('xiaoman'));
78	  if (!page) throw new Error('未找到 OKKI 页面');
