131	          orderCount: c.performance_order_count || 0,
132	          orderAmount: c.transaction_order_amount || 0,
133	          contactCount: c.customer_contact_count || 0,
134	          archiveTime: c.archive_time || '',
135	          orderTime: c.order_time || '',
136	          serialNumber: c.serial_id || '',
137	        },
138	        // 邮件跟进记录
139	        trails: {
140	          total: trailRes.data?.totalItem || trails.length,
141	          tabList: trailRes.data?.tab_list || [],
142	          items: trails.map(t => ({
143	            id: t.trail_id,
144	            type: t.type,
145	            typeName: t.node_type_name,
146	            createdAt: t.created_at || t.create_time,
147	            data: t.data || {},
148	            commentList: t.comment_list || [],
149	          })),
150	        },
151	        // 客户详情
152	        detail: Object.fromEntries(
153	          Object.entries(detail).map(([k, v]) => [k, v?.info_label || v?.info_value || v])
154	        ),
155	      };
156	
157	      fs.writeFileSync(path.join(OUTPUT_DIR, cid + '.json'), JSON.stringify(output, null, 2));
158	
159	      state.customers[cid] = { name, archiveTime: lastArchive, scrapedAt: output.scrapedAt };
160	      done++;
161	
162	      if (done % BATCH_SIZE === 0) {
163	        console.log('[API Batch] ' + done + '/' + targets.length + ' (' + skipped + ' skipped, ' + errors + ' errors)');
164	        saveState(state);
165	      }
166	    } catch (e) {
